mapper.sql:
    SELECT
            ID,
PROVINCE_CODE,
CITY_CODE,
AREA_CODE,
NAME,
CODE,
REC_NAM,
REC_TIM,
UPD_NAM,
UPD_TIM,
IDEV_VERSIONUSE,
OBJ,
MAP,
IS_CK
    FROM
        M_CITY


            and ID = #{id}


            and PROVINCE_CODE = #{provinceCode}


            and CITY_CODE = #{cityCode}


            and AREA_CODE = #{areaCode}


            and NAME = #{name}


            and CODE = #{code}


            and REC_NAM = #{recNam}


            and REC_TIM = #{recTim}


            and UPD_NAM = #{updNam}


            and UPD_TIM = #{updTim}


            and IDEV_VERSIONUSE = #{idevVersionuse}


            and OBJ = #{obj}


            and MAP = #{map}


            and IS_CK = #{isCk}
